import { readFileSync } from "node:fs";
import { join } from "node:path";
import { computeReachableSteps, Flow, nextRefsForMode, renderFlow, renderMarkdown, TARGETS, } from "bitfab-flow";
import { describe, expect, it } from "vitest";
import { assistantFlow } from "./assistant.js";
const REPO_ROOT = join(__dirname, "..", "..", "..");
const ASSISTANT_PATHS = {
    claude: "bitfab-claude-plugin/skills/assistant/SKILL.md",
    cursor: "bitfab-cursor-plugin/skills/bitfab-assistant/SKILL.md",
    codex: "bitfab-codex-plugin/skills/assistant/SKILL.md",
};
/** Returns the rendered body text of a step (searched across all phases). */
function findStepBody(stepId) {
    for (const phase of assistantFlow.phases) {
        const step = phase.steps.find((s) => s.id === stepId);
        if (step && "body" in step && typeof step.body === "string") {
            return step.body;
        }
    }
    throw new Error(`step "${stepId}" not found or has no body`);
}
describe("renderMarkdown(assistantFlow)", () => {
    for (const targetName of Object.keys(ASSISTANT_PATHS)) {
        it(`matches the committed ${targetName} assistant skill byte-for-byte`, () => {
            const target = TARGETS[targetName];
            const generated = renderMarkdown(assistantFlow, target);
            const committedPath = join(REPO_ROOT, ASSISTANT_PATHS[targetName]);
            const committed = readFileSync(committedPath, "utf-8");
            expect(generated).toBe(committed);
        });
    }
});
describe("assistantFlow: read_traces scope choices", () => {
    it("requires trace evidence before root-cause recommendations", () => {
        const output = renderMarkdown(assistantFlow, TARGETS.codex);
        expect(output).toContain("Trace-first debugging rule");
        expect(output).toContain("do not declare root cause, recommend a revert/no-revert, or propose the fix path");
        expect(output).toContain("Do not stop after `list_trace_functions`");
    });
    it("investigate mode identifies function keys from code before listing functions", () => {
        const body = findStepBody("gather-context");
        expect(body).toContain("First inspect the local instrumentation to infer likely function keys");
        expect(body).toContain("`observability/providers/bitfab`");
        expect(body).toContain("Then call {{tool:listFunctions}} to confirm whether the candidate has traces");
    });
    // Small scan / triage / lookup reads call read_traces directly with "summary":
    // bounded per-span truncation so a batch of candidate traces stays small.
    it.each([
        ["find-unlabeled"],
        ["check-replay-health"],
    ])('%s reads scope "summary"', (stepId) => {
        expect(findStepBody(stepId)).toContain('scope: "summary"');
    });
    // The free-form explore step lets the agent choose either scope.
    it("explore offers both summary and full", () => {
        const body = findStepBody("explore");
        expect(body).toContain('scope: "summary"');
        expect(body).toContain('"full"');
    });
    // Bulk reads of >10 traces go through the readTracesBatched command, which
    // does the batch-of-10 parallel fan-out deterministically instead of asking
    // the agent to issue the calls itself ("in parallel in a single turn").
    it("resolve-context fans out batched reads via readTracesBatched (summary)", () => {
        const body = findStepBody("resolve-context");
        expect(body).toContain("{{command:readTracesBatched}}");
        expect(body).toContain("--scope summary");
        expect(body).not.toContain("in parallel in a single turn");
    });
    it("label-self fans out batched reads via readTracesBatched (full)", () => {
        const body = findStepBody("label-self");
        expect(body).toContain("{{command:readTracesBatched}}");
        expect(body).toContain("--scope full");
        expect(body).not.toContain("in parallel in a single turn");
    });
    // build-dataset gates the label load on costRun: the common quality run uses
    // the single-call read_trace_labels tool; a cost run needs each original's
    // recorded token usage, so it loads full traces via readTracesBatched (the
    // deterministic fan-out, not the agent-driven one).
    it("build-dataset gates the label load on costRun", () => {
        const body = findStepBody("build-dataset");
        expect(body).toContain("{{tool:readTraceLabels}}");
        expect(body).toContain("costRun");
        // read_trace_labels caps at 100 IDs, so a >100-trace dataset must chunk.
        expect(body).toContain("chunks of 100");
        // Cost-run branch loads full traces for token usage via the batched command.
        expect(body).toContain("{{command:readTracesBatched}}");
        expect(body).toContain("--scope full");
        expect(body).not.toContain("in parallel in a single turn");
    });
    // seed-from-existing-labels loads labels + annotations of already-validated
    // traces (no re-labeling), so it uses the dedicated read_trace_labels tool
    // and drops the old scope:"summary" read.
    it("seed-from-existing-labels uses readTraceLabels, not scope summary", () => {
        const body = findStepBody("seed-from-existing-labels");
        expect(body).toContain("{{tool:readTraceLabels}}");
        expect(body).not.toContain('scope: "summary"');
        // Step 1 can dedupe >100 IDs; step 2 must chunk to the tool's 100 cap.
        expect(body).toContain("chunks of 100");
    });
});
