describe("assistantFlow: detect-replay-capabilities", () => {
    it("detect-replay-capabilities exists in both verify-instrumentation and iterate", () => {
        const phase2 = assistantFlow.phases.find((p) => p.id === "verify-instrumentation");
        const phase5 = assistantFlow.phases.find((p) => p.id === "iterate");
        expect(phase2?.steps.find((s) => s.id === "detect-replay-capabilities")).toBeDefined();
        expect(phase5?.steps.find((s) => s.id === "detect-replay-capabilities")).toBeDefined();
    });
    it("upgrade-replay-script exists in both verify-instrumentation and iterate", () => {
        const phase2 = assistantFlow.phases.find((p) => p.id === "verify-instrumentation");
        const phase5 = assistantFlow.phases.find((p) => p.id === "iterate");
        expect(phase2?.steps.find((s) => s.id === "upgrade-replay-script")).toBeDefined();
        expect(phase5?.steps.find((s) => s.id === "upgrade-replay-script")).toBeDefined();
    });
    it("both detect steps are reachable for all targets", () => {
        for (const targetName of ["claude", "cursor", "codex"]) {
            const reachable = computeReachableSteps(assistantFlow, targetName);
            expect(reachable.has("verify-instrumentation/detect-replay-capabilities")).toBe(true);
            expect(reachable.has("iterate/detect-replay-capabilities")).toBe(true);
        }
    });
    it("categorize-fixes routes to iterate detect-replay-capabilities", () => {
        const phase4 = assistantFlow.phases.find((p) => p.id === "diagnose");
        expect(phase4).toBeDefined();
        const categorize = phase4?.steps.find((s) => s.id === "categorize-fixes");
        expect(categorize?.kind).toBe("action");
        if (categorize?.kind !== "action") {
            throw new Error("expected action step");
        }
        const nextVal = categorize.next;
        expect(nextVal).not.toBeNull();
        if (typeof nextVal === "string") {
            expect(nextVal).toContain("detect-replay-capabilities");
        }
        else if (nextVal !== null) {
            for (const v of Object.values(nextVal.byMode)) {
                if (v !== null && v !== "cleanup/close-studio") {
                    expect(v).toContain("detect-replay-capabilities");
                }
            }
        }
    });
    it("iterate detect-replay-capabilities auto-skips when all flags present", () => {
        const phase5 = assistantFlow.phases.find((p) => p.id === "iterate");
        expect(phase5).toBeDefined();
        const detect = phase5?.steps.find((s) => s.id === "detect-replay-capabilities");
        expect(detect?.kind).toBe("branch");
        if (detect?.kind !== "branch") {
            throw new Error("expected branch step");
        }
        const autoSkip = detect.branches.find((b) => b.when?.includes("all flags"));
        expect(autoSkip?.next).toBe("iterate/open-experiments-before-replay");
    });
    it("iterate upgrade-replay-script continues to open-experiments-before-replay", () => {
        const phase5 = assistantFlow.phases.find((p) => p.id === "iterate");
        expect(phase5).toBeDefined();
        const upgrade = phase5?.steps.find((s) => s.id === "upgrade-replay-script");
        expect(upgrade?.kind).toBe("action");
        if (upgrade?.kind !== "action") {
            throw new Error("expected action step");
        }
        expect(upgrade.next).toBe("iterate/open-experiments-before-replay");
    });
    it("share-results loops back to open-experiments-before-replay", () => {
        const phase5 = assistantFlow.phases.find((p) => p.id === "iterate");
        expect(phase5).toBeDefined();
        const share = phase5?.steps.find((s) => s.id === "share-results");
        expect(share?.kind).toBe("branch");
        if (share?.kind !== "branch") {
            throw new Error("expected branch step");
        }
        const continueBranch = share.branches.find((b) => b.next === "iterate/open-experiments-before-replay");
        expect(continueBranch).toBeDefined();
    });
});
describe("assistantFlow: replay mode (minimal single-trace)", () => {
    it("replay entry goes straight to quick-replay/setup, never through Studio", () => {
        // Non-codex targets must skip studio/open entirely for replay.
        const entry = assistantFlow.entries.replay;
        if (entry === undefined || typeof entry === "string") {
            throw new Error("expected a per-target entry object for replay");
        }
        expect(entry.default).toBe("quick-replay/setup");
    });
    it("codex replay still resolves the plugin dir, then jumps to quick-replay/setup", () => {
        const entry = assistantFlow.entries.replay;
        if (entry === undefined || typeof entry === "string") {
            throw new Error("expected a per-target entry object for replay");
        }
        expect(entry.codex).toBe("preamble/resolve-plugin-dir");
        const phase0 = assistantFlow.phases.find((p) => p.id === "preamble");
        const runStatus = phase0?.steps.find((s) => s.id === "run-status");
        expect(runStatus?.kind).toBe("action");
        if (runStatus?.kind !== "action") {
            throw new Error("expected action step");
        }
        const next = runStatus.next;
        if (next === null || typeof next === "string") {
            throw new Error("expected byMode next");
        }
        expect(next.byMode.replay).toBe("quick-replay/setup");
        // The other modes still open Studio.
        expect(next.byMode.wizard).toBe("studio/open");
    });
    it("quick-replay steps are reachable for all targets", () => {
        for (const targetName of ["claude", "cursor", "codex"]) {
            const reachable = computeReachableSteps(assistantFlow, targetName);
            expect(reachable.has("quick-replay/setup")).toBe(true);
            expect(reachable.has("quick-replay/run")).toBe(true);
            expect(reachable.has("quick-replay/verdict")).toBe(true);
            expect(reachable.has("quick-replay/iterate")).toBe(true);
        }
    });
    it("setup exits to cleanup when no replay script or trace is found", () => {
        const phaseReplay = assistantFlow.phases.find((p) => p.id === "quick-replay");
        const setup = phaseReplay?.steps.find((s) => s.id === "setup");
        expect(setup?.kind).toBe("branch");
        if (setup?.kind !== "branch") {
            throw new Error("expected branch step");
        }
        const noScript = setup.branches.find((b) => (b.when ?? "").includes("no replay script"));
        expect(noScript?.next).toBe("cleanup/close-studio");
        const noTrace = setup.branches.find((b) => (b.when ?? "").includes("trace not found"));
        expect(noTrace?.next).toBe("cleanup/close-studio");
        const ok = setup.branches.find((b) => (b.when ?? "").includes("found and trace readable"));
        expect(ok?.next).toBe("quick-replay/run");
    });
    it("run flows into verdict, and verdict's iterate branch loops back to run", () => {
        const phaseReplay = assistantFlow.phases.find((p) => p.id === "quick-replay");
        const run = phaseReplay?.steps.find((s) => s.id === "run");
        expect(run?.kind).toBe("action");
        if (run?.kind !== "action") {
            throw new Error("expected action step");
        }
        expect(run.next).toBe("quick-replay/verdict");
        const verdict = phaseReplay?.steps.find((s) => s.id === "verdict");
        expect(verdict?.kind).toBe("branch");
        if (verdict?.kind !== "branch") {
            throw new Error("expected branch step");
        }
        const iterate = verdict.branches.find((b) => b.next === "quick-replay/iterate");
        expect(iterate).toBeDefined();
        const iterateStep = phaseReplay?.steps.find((s) => s.id === "iterate");
        expect(iterateStep?.kind).toBe("action");
        if (iterateStep?.kind !== "action") {
            throw new Error("expected action step");
        }
        expect(iterateStep.next).toBe("quick-replay/run");
    });
    it("minimal replay invokes no plugin commands (no persistence, no Studio navigation)", () => {
        const phaseReplay = assistantFlow.phases.find((p) => p.id === "quick-replay");
        const bodies = (phaseReplay?.steps ?? [])
            .map((s) => ("body" in s ? (s.body ?? "") : ""))
            .join("\n");
        // No `{{command:...}}` interpolations means no openStudio / persistReplayLabels
        // calls in the step bodies - the path runs entirely in-chat off the user's
        // own replay script. (The run step mentions --code-change / --experiment-group-id
        // only to instruct the agent NOT to pass them.)
        expect(bodies).not.toContain("{{command:");
        expect(bodies).not.toContain("persistReplayLabels");
    });
});
describe("assistantFlow: fix routing", () => {
    for (const targetName of Object.keys(ASSISTANT_PATHS)) {
        it(`routes descriptive find-and-fix trace anchors to fix for ${targetName}`, () => {
            const out = renderMarkdown(assistantFlow, TARGETS[targetName]);
            expect(out).toContain('"find and fix the trace where <bad behavior happened>"');
            expect(out).toContain("The trace anchor can be a trace ID **or a smoking-gun description to search for**");
            expect(out).toContain('If the user says **"find and fix"** / **"search ... and fix"** / **"fix the trace where ..."**, route to `fix`, not `investigate`');
            expect(out).toContain("If there is no UUID but the user gave a **smoking-gun description**");
            expect(out.indexOf("**First, sanity-check the anchor:**")).toBeLessThan(out.indexOf("If there is no UUID but the user gave a **smoking-gun description**"));
            expect(out).toContain("inspect the local instrumentation");
            expect(out).toContain("with the descriptive terms");
        });
    }
});
