describe("assistantFlow: cost-optimize mode", () => {
    it("cost-optimize entry mirrors experiment: opens Studio (codex resolves plugin dir first)", () => {
        const entry = assistantFlow.entries["cost-optimize"];
        if (entry === undefined || typeof entry === "string") {
            throw new Error("expected a per-target entry object for cost-optimize");
        }
        expect(entry.default).toBe("studio/open");
        expect(entry.codex).toBe("preamble/resolve-plugin-dir");
    });
    it("studio/open routes cost-optimize to load-dataset/pick-dataset", () => {
        const studio = assistantFlow.phases.find((p) => p.id === "studio");
        const open = studio?.steps.find((s) => s.id === "open");
        if (open?.kind !== "action") {
            throw new Error("expected action step");
        }
        const next = open.next;
        if (next === null || typeof next === "string") {
            throw new Error("expected byMode next");
        }
        expect(next.byMode["cost-optimize"]).toBe("load-dataset/pick-dataset");
    });
    it("pick-dataset routes cost-optimize into the dedicated cost-diagnosis phase", () => {
        const loadDataset = assistantFlow.phases.find((p) => p.id === "load-dataset");
        const pick = loadDataset?.steps.find((s) => s.id === "pick-dataset");
        if (pick?.kind !== "branch") {
            throw new Error("expected branch step");
        }
        const success = pick.branches.find((b) => (b.when ?? "").includes("dataset loaded"));
        const next = success?.next;
        if (next === null || next === undefined || typeof next === "string") {
            throw new Error("expected byMode next");
        }
        expect(next.byMode["cost-optimize"]).toBe("cost/diagnose");
        // experiment still goes straight to the loop (no cost diagnosis).
        expect(next.byMode.experiment).toBe("load-dataset/pick-execution-mode");
    });
    it("cost-diagnosis phase rejoins the shared replay loop at pick-execution-mode", () => {
        const cost = assistantFlow.phases.find((p) => p.id === "cost");
        expect(cost).toBeDefined();
        const diagnose = cost?.steps.find((s) => s.id === "diagnose");
        if (diagnose?.kind !== "action") {
            throw new Error("expected action step");
        }
        expect(diagnose.next).toBe("load-dataset/pick-execution-mode");
    });
    it("cost/diagnose is reachable for all targets", () => {
        for (const targetName of ["claude", "cursor", "codex"]) {
            const reachable = computeReachableSteps(assistantFlow, targetName);
            expect(reachable.has("cost/diagnose")).toBe(true);
        }
    });
    it("documents that cost-optimize forces costRun on, with the basis still inferred", () => {
        for (const targetName of Object.keys(ASSISTANT_PATHS)) {
            const out = renderMarkdown(assistantFlow, TARGETS[targetName]);
            expect(out).toContain("`cost-optimize`");
            expect(out).toContain("`costRun` is always true");
        }
    });
});
