describe("assistantFlow: token-cost (costRun) wiring", () => {
    for (const targetName of Object.keys(ASSISTANT_PATHS)) {
        it(`establishes the costRun flag and wires the token-cost lens for ${targetName}`, () => {
            const out = renderMarkdown(assistantFlow, TARGETS[targetName]);
            // The flag is classified once, in argument routing.
            expect(out).toContain("Token-cost goal (`costRun`)");
            expect(out).toContain("`costRun = true`");
            // The experiments-page URLs carry a flag-gated <tokensSuffix> slot inline
            // (not an afterthought below the block), resolved from costRun. This is
            // symmetric: it neither bakes in &tokens=1 (over-application on quality
            // runs) nor leaves it out (under-application on cost runs).
            expect(out).toContain("experimentGroupId=<experimentGroupId><tokensSuffix>");
            expect(out).toContain("experimentGroupId=<experimentGroupId>&mode=benchmark<tokensSuffix>");
            // The slot must be explained as a costRun-gated substitution, and the
            // raw &tokens=1 must NOT be hard-coded into the group-ID URLs.
            expect(out).toContain("`<tokensSuffix>` is a real placeholder");
            expect(out).not.toContain("experimentGroupId=<experimentGroupId>&tokens=1");
            // Token deltas are reported alongside pass/fail in all three report steps.
            expect(out).toContain("capture the token delta for each completed item");
            expect(out).toContain("lead with the token delta");
            expect(out).toContain("add token cost to both tables");
            // The token basis (all vs uncached) is classified alongside costRun, and
            // <tokensSuffix> resolves to the uncached variant only on that basis. The
            // default (all) never carries tokenType.
            expect(out).toContain("Token basis (`tokenType`)");
            expect(out).toContain("`costBasis`");
            expect(out).toContain("`&tokens=1&tokenType=uncached`");
            // The chat-side reports follow the same basis as the page lens, so the
            // numbers never disagree with the cyan/orange uncached trend.
            expect(out).toContain("`(input - cached) + output`");
            expect(out).toContain("so the chat numbers match the page lens");
        });
    }
});
// The assistant ships monolith, but the flow is deliberately kept
// split-chain-compatible: semantic phase ids double as sub-skill names, and
// Phase 5 is pre-split so every cross-phase dispatch lands on a phase's first
// step. This suite forces split-chain in-memory so flipping `compile.mode` to
// "split-chain" stays a safe one-line change and can't silently rot.
describe("assistantFlow: split-chain compatibility (not shipped)", () => {
    const splitFlow = Flow.parse({
        ...assistantFlow,
        compile: { mode: "split-chain", inlinePhases: [] },
    });
    it("passes the split-chain structural guards (first-step entries, no inline re-entry)", () => {
        // Flow.parse above throws if a guard fails; reaching here means it parsed.
        expect(splitFlow.id).toBe("assistant");
    });
    it("compiles to an orchestrator + per-phase sub-skills, no unresolved tokens", () => {
        const files = renderFlow(splitFlow, TARGETS.claude);
        const kinds = files.map((f) => f.kind);
        expect(kinds.filter((k) => k === "orchestrator")).toHaveLength(1);
        // One sub-skill per claude-reachable phase (preamble is codex-only).
        expect(kinds.filter((k) => k === "phase").length).toBeGreaterThanOrEqual(12);
        expect(files.some((f) => f.slug === "preamble")).toBe(false);
        for (const file of files) {
            expect(file.content.match(/\{\{[^}]*\}\}/g), `unresolved tokens in ${file.slug || file.kind}`).toBeNull();
        }
    });
});
describe("assistantFlow: split-chain dispatch integrity", () => {
    const STEP_BY_ID = new Map();
    for (const phase of assistantFlow.phases) {
        for (const step of phase.steps) {
            STEP_BY_ID.set(`${phase.id}/${step.id}`, step);
        }
    }
    function entryStart(entry) {
        if (typeof entry === "string") {
            return entry;
        }
        const resolved = entry.claude ?? entry.default;
        if (resolved === undefined) {
            throw new Error("entry has no resolvable start step");
        }
        return resolved;
    }
    function walkChain(mode, start) {
        const visited = new Set();
        const terminals = new Set();
        const queue = [start];
        while (queue.length > 0) {
            const id = queue.shift();
            if (id === null || id === undefined || visited.has(id)) {
                continue;
            }
            visited.add(id);
            const step = STEP_BY_ID.get(id);
            if (step === undefined) {
                throw new Error(`mode "${mode}": Next ref "${id}" has no matching step`);
            }
            const refs = nextRefsForMode(step, mode);
            if (refs.every((ref) => ref === null)) {
                terminals.add(id);
            }
            for (const ref of refs) {
                queue.push(ref);
            }
        }
        return { visited, terminals };
    }
    it("every Next ref in every mode resolves to a real step or null", () => {
        const validIds = new Set(STEP_BY_ID.keys());
        for (const mode of Object.keys(assistantFlow.entries)) {
            for (const [id, step] of STEP_BY_ID) {
                for (const ref of nextRefsForMode(step, mode)) {
                    if (ref !== null) {
                        expect(validIds.has(ref), `mode "${mode}" step "${id}" routes to missing step "${ref}"`).toBe(true);
                    }
                }
            }
        }
    });
    // Studio modes (and Studio-less but cleanup-routed `replay`) tail into cleanup
    // so closeStudio.js always runs; `add-trace` never opens Studio and terminates
    // at its own attach step.
    const EXPECTED_TERMINAL = {
        wizard: "cleanup/close-studio",
        dataset: "cleanup/close-studio",
        experiment: "cleanup/close-studio",
        "cost-optimize": "cleanup/close-studio",
        investigate: "cleanup/close-studio",
        benchmark: "cleanup/close-studio",
        replay: "cleanup/close-studio",
        fix: "cleanup/close-studio",
        "add-trace": "add-trace/attach",
    };
    it("every mode's dispatch chain converges on its single expected terminal", () => {
        for (const [mode, entry] of Object.entries(assistantFlow.entries)) {
            const { visited, terminals } = walkChain(mode, entryStart(entry));
            const expected = EXPECTED_TERMINAL[mode];
            expect(expected, `unmapped mode "${mode}"`).toBeDefined();
            expect(visited.has(expected), `mode "${mode}" never reaches ${expected}`).toBe(true);
            expect([...terminals].sort(), `mode "${mode}" has unexpected terminal steps`).toEqual([expected]);
        }
    });
    it("experiment/benchmark enter Phase 5 (iterate) via load-dataset; wizard enters iterate from diagnose", () => {
        const experiment = walkChain("experiment", entryStart(assistantFlow.entries.experiment)).visited;
        expect(experiment.has("load-dataset/pick-dataset")).toBe(true);
        expect(experiment.has("load-dataset/pick-execution-mode")).toBe(true);
        expect(experiment.has("iterate/detect-replay-capabilities")).toBe(true);
        const benchmark = walkChain("benchmark", entryStart(assistantFlow.entries.benchmark)).visited;
        expect(benchmark.has("load-dataset/pick-dataset")).toBe(true);
        expect(benchmark.has("load-dataset/pick-execution-mode")).toBe(false);
        expect(benchmark.has("iterate/detect-replay-capabilities")).toBe(true);
        const wizard = walkChain("wizard", entryStart(assistantFlow.entries.wizard)).visited;
        expect(wizard.has("load-dataset/pick-dataset")).toBe(false);
        expect(wizard.has("diagnose/categorize-fixes")).toBe(true);
        expect(wizard.has("iterate/detect-replay-capabilities")).toBe(true);
    });
    it("fix mode reaches its test-first capture / save / rerun steps", () => {
        const fix = walkChain("fix", entryStart(assistantFlow.entries.fix)).visited;
        // The verdict split runs before any capture, so dataset capture is
        // downstream of the single-trace replay result (the test-first invariant).
        expect(fix.has("iterate/fix-target-replay-status")).toBe(true);
        expect(fix.has("iterate/fix-capture")).toBe(true);
        expect(fix.has("iterate/fix-save-unfixed")).toBe(true);
        expect(fix.has("iterate/fix-rerun-dataset-mode")).toBe(true);
    });
    it("fix save-unfixed only marks capture after attach is confirmed", () => {
        const body = findStepBody("fix-save-unfixed");
        expect(body).toContain("Confirm the attach landed");
        expect(body).toContain("do **not** set `fixCaptured`");
        expect(body).toContain("Set `fixCaptured = true` only once the attach above is confirmed");
    });
});
describe("assistantFlow: AskUserQuestion option cap", () => {
    // AskUserQuestion renders at most 4 options; a branch step that lists more
    // would silently overflow the picker. Routing-only (`when`) branches don't
    // render options, so only count branches that carry an `option`.
    it("no branch step renders more than 4 user-facing options", () => {
        const ASK_CAP = 4;
        for (const phase of assistantFlow.phases) {
            for (const step of phase.steps) {
                if (step.kind !== "branch" || !Array.isArray(step.branches)) {
                    continue;
                }
                const optionCount = step.branches.filter((b) => b.option).length;
                if (optionCount === 0) {
                    continue;
                }
                expect(optionCount, `step "${phase.id}/${step.id}" renders ${optionCount} options; AskUserQuestion caps at ${ASK_CAP}`).toBeLessThanOrEqual(ASK_CAP);
            }
        }
    });
});
